import{_ as t,c as a,a3 as r,o as n}from"./chunks/framework.tbYQZw9U.js";const u=JSON.parse('{"title":"启蒙思想下的中国科技焦虑","description":"","frontmatter":{"prev":false,"next":false,"date":"2025-02-06T00:00:00.000Z","tags":["知乎好文"],"categories":["转裁"]},"headers":[],"relativePath":"2025/02/Tech_Anxiety_in_China.md","filePath":"2025/02/Tech_Anxiety_in_China.md","lastUpdated":1738854479000}'),i={name:"2025/02/Tech_Anxiety_in_China.md"};function s(o,e,l,p,h,c){return n(),a("div",null,e[0]||(e[0]=[r('<h1 id="启蒙思想下的中国科技焦虑" tabindex="-1">启蒙思想下的中国科技焦虑 <a class="header-anchor" href="#启蒙思想下的中国科技焦虑" aria-label="Permalink to &quot;启蒙思想下的中国科技焦虑&quot;">​</a></h1><p>刷知乎刷到一篇好文章，忍不住，转裁过来，知乎的原问题是</p><ul><li><a href="https://www.zhihu.com/question/658210607" target="_blank" rel="noreferrer">斯坦福大学AI指数报告称：中国人对AI态度最为积极，你如何解读这个观点？</a></li></ul><p>被转裁到站内另一个问题下</p><ul><li><a href="https://www.zhihu.com/question/11014237507/answer/93132090873" target="_blank" rel="noreferrer">为什么deepseek没有出现在美国?</a></li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>原网址：<a href="https://www.zhihu.com/question/658210607/answer/3533755480" target="_blank" rel="noreferrer">https://www.zhihu.com/question/658210607/answer/3533755480</a></p></div><p>只能说过去半个世纪基于 “百年国耻” 的历史叙事实在太成功了，它是如此深刻地塑造了如今地球上最奇特的进步主义地上神国，堪称启蒙思想家们的理想天堂。这几天看知乎/公众号上各种关于黄仁勋和马斯克的文章，就感觉几乎无论是哪个阵营，都像是依然活在教科书里的鸦片战争时代一样。对一个国家的最高评价就是 “船坚炮利”，不愿意承认这一点的国家很快就会被军舰开上门，然后永世不得翻身。整个国家只有自己是 “开眼看世界的先行者”，其他人亟待自己启蒙，如果启蒙不了那就是 “思想配得上苦难” 。</p><p>这样的焦虑感与深切的自卑感，在全世界其他200多个国家都极少见到：没人写文章质问英伟达为什么没诞生在印度或者韩国，仿佛那是理所应该发生的事情；《纽约时报》前主编不会呼吁美国必须将光刻机研发水平提升到 “不大幅落后ASML的水平”，否则就会产生 “一系列国家安全后果”；即便是世界上最贫困的国家，也几乎没有人会像现在的中国人一样，成天焦虑什么 “是不是又错过了第四次工业革命” ——或者说，错过了又怎么样呢？印度或者尼日利亚跟第几次工业革命都没有关系，我看天也没有塌，地也没有陷，女人还在生小孩——而且生的还很多，说明人家幸福感很高。</p><p>知乎上某些人喜欢阴阳怪气的 “不要讲究什么科学，要注重礼法教化”，这才是人类历史上绝大多数社会的常态。而且这非常合理：科技发展具有无条件的优先性，整个社会及其成员的生活、数千年的文化与制度都必须为科技发展服务，这种观念不仅没有先验的正确性，而且绝对是反直觉的，它让人类社会成为了科技的奴隶，而不是让科技为人类服务。</p><p>一个属于正常人的社会，就应该理直气壮地让科技发展服从于礼法教化、服从于社会需求和社会规范。不利于社会和谐稳定、不利于促进多数人福祉和完善的科技发展，就是要坚决扼杀在摇篮里。否则这个世界到底是人类的，还是科技的？第一次工业革命时期的英国工人被纺织机砸了饭碗，还会组织卢德运动砸毁机器，但在中国从来没有人会怀疑自动化的进程越快越好，因为那是 “先进生产力”，是 “科技进步的趋势”，人们只会担心中国的生产自动化水平还不够；ChatGPT/sora/星舰 一出来，国内的互联网都在反思 “为什么没诞生在中国”，不反思的则会辩护 “中国的AI/航天一点也不差”，而几乎没有任何人质疑人工智能对社会到底是不是好事。管理层更是对各种技术进步极其重视， “科技应该服从社会需求” “科技发展本身不是目的” 这种想法在国内居然只会被嘲讽。</p><p>真是匪夷所思。应该说，现在在全世界范围内都已经不大能找到比中国更符合当年启蒙主义图景的国家了：社会思想高度世俗化，政治经济各方面制度都建立在理性主义基础上，社会普遍对于 “人可以认识并利用规律改造世界” 深信不疑，普遍坚信历史进步论，全社会从上到下推崇自然科学及其研究方法，对 “人文情怀” 充满鄙视……这真是伏尔泰见了都得直呼太启蒙了。所以谁能跟我说说，那些鼓吹 “中国缺乏科学精神” “启蒙失败” 的人到底是怎么想的？</p>',11)]))}const d=t(i,[["render",s]]);export{u as __pageData,d as default};
